const ASSETS = {"/index.html":{"body":"<!doctype html>\n<html lang=\"da\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <meta name=\"theme-color\" content=\"#0f766e\" />\n    <title>Trafikalarm</title>\n    <link rel=\"manifest\" href=\"manifest.json\" />\n    <link rel=\"stylesheet\" href=\"styles.css\" />\n  </head>\n  <body>\n    <svg class=\"icon-sprite\" aria-hidden=\"true\">\n      <symbol id=\"icon-bell\" viewBox=\"0 0 24 24\">\n        <path d=\"M6 9a6 6 0 1 1 12 0c0 7 3 6 3 8H3c0-2 3-1 3-8Z\"></path>\n        <path d=\"M10 21h4\"></path>\n      </symbol>\n      <symbol id=\"icon-route\" viewBox=\"0 0 24 24\">\n        <circle cx=\"6\" cy=\"19\" r=\"3\"></circle>\n        <circle cx=\"18\" cy=\"5\" r=\"3\"></circle>\n        <path d=\"M9 19h2a5 5 0 0 0 0-10H9a3 3 0 0 1 0-6h6\"></path>\n      </symbol>\n      <symbol id=\"icon-play\" viewBox=\"0 0 24 24\">\n        <path d=\"m8 5 11 7-11 7Z\"></path>\n      </symbol>\n      <symbol id=\"icon-pen\" viewBox=\"0 0 24 24\">\n        <path d=\"M12 20h9\"></path>\n        <path d=\"M16.5 3.5a2.1 2.1 0 0 1 3 3L7 19l-4 1 1-4Z\"></path>\n      </symbol>\n      <symbol id=\"icon-trash\" viewBox=\"0 0 24 24\">\n        <path d=\"M3 6h18\"></path>\n        <path d=\"M8 6V4h8v2\"></path>\n        <path d=\"M6 6l1 15h10l1-15\"></path>\n      </symbol>\n      <symbol id=\"icon-mail\" viewBox=\"0 0 24 24\">\n        <path d=\"M4 5h16v14H4Z\"></path>\n        <path d=\"m4 7 8 6 8-6\"></path>\n      </symbol>\n      <symbol id=\"icon-user\" viewBox=\"0 0 24 24\">\n        <circle cx=\"12\" cy=\"8\" r=\"4\"></circle>\n        <path d=\"M4 21a8 8 0 0 1 16 0\"></path>\n      </symbol>\n    </svg>\n\n    <div class=\"app-shell\">\n      <header class=\"topbar\">\n        <div class=\"brand\">\n          <div class=\"brand-mark\">TA</div>\n          <div>\n            <h1>Trafikalarm</h1>\n            <p>Rutevarsling til pendleren</p>\n          </div>\n        </div>\n        <div class=\"topbar-actions\">\n          <div class=\"system-status\" id=\"systemStatus\">Klar til tjek</div>\n          <button class=\"button secondary\" id=\"requestNotifications\" type=\"button\">\n            <svg><use href=\"#icon-bell\"></use></svg>\n            Aktiver push\n          </button>\n        </div>\n      </header>\n\n      <main class=\"workspace\">\n        <section class=\"auth-banner\" id=\"authBanner\">\n          <div>\n            <strong>Opret din pendlerprofil</strong>\n            <span>Prototypen gemmer dine valg lokalt i browseren.</span>\n          </div>\n          <form id=\"quickProfileForm\" class=\"quick-profile\">\n            <label>\n              Navn\n              <input id=\"quickName\" name=\"quickName\" autocomplete=\"name\" placeholder=\"Dit navn\" />\n            </label>\n            <label>\n              Mail\n              <input id=\"quickEmail\" name=\"quickEmail\" type=\"email\" autocomplete=\"email\" placeholder=\"navn@example.dk\" />\n            </label>\n            <button class=\"button primary\" type=\"submit\">Gem profil</button>\n          </form>\n        </section>\n\n        <section class=\"panel profile-panel\" aria-labelledby=\"profileTitle\">\n          <div class=\"panel-heading\">\n            <div>\n              <p class=\"eyebrow\">Profil</p>\n              <h2 id=\"profileTitle\">Pendler og tider</h2>\n            </div>\n            <svg class=\"panel-icon\"><use href=\"#icon-user\"></use></svg>\n          </div>\n\n          <form id=\"profileForm\" class=\"form-stack\">\n            <div class=\"field-grid\">\n              <label>\n                Navn\n                <input id=\"nameInput\" name=\"name\" autocomplete=\"name\" placeholder=\"Dit navn\" />\n              </label>\n              <label>\n                Mail til varsler\n                <input id=\"emailInput\" name=\"email\" type=\"email\" autocomplete=\"email\" placeholder=\"navn@example.dk\" />\n              </label>\n            </div>\n\n            <div class=\"field-grid\">\n              <label>\n                Hjem\n                <input id=\"homeInput\" name=\"home\" list=\"homeSuggestions\" autocomplete=\"street-address\" placeholder=\"fx Frederiksberg\" />\n                <datalist id=\"homeSuggestions\"></datalist>\n              </label>\n              <label>\n                Arbejde\n                <input id=\"workInput\" name=\"work\" list=\"workSuggestions\" autocomplete=\"street-address\" placeholder=\"fx Nordhavn\" />\n                <datalist id=\"workSuggestions\"></datalist>\n              </label>\n            </div>\n\n            <div class=\"section-label\">Rute</div>\n            <div class=\"segmented\" role=\"tablist\" aria-label=\"Vælg rute\">\n              <button class=\"segment active\" id=\"modeWork\" type=\"button\" data-mode=\"work\">Til arbejde</button>\n              <button class=\"segment\" id=\"modeHome\" type=\"button\" data-mode=\"home\">Hjem</button>\n            </div>\n\n            <div class=\"section-label\">Ugedage</div>\n            <div class=\"days\" id=\"daysGroup\" aria-label=\"Vælg dage\">\n              <label><input type=\"checkbox\" value=\"mon\" /> Man</label>\n              <label><input type=\"checkbox\" value=\"tue\" /> Tir</label>\n              <label><input type=\"checkbox\" value=\"wed\" /> Ons</label>\n              <label><input type=\"checkbox\" value=\"thu\" /> Tor</label>\n              <label><input type=\"checkbox\" value=\"fri\" /> Fre</label>\n              <label><input type=\"checkbox\" value=\"sat\" /> Lør</label>\n              <label><input type=\"checkbox\" value=\"sun\" /> Søn</label>\n            </div>\n\n            <div class=\"time-grid\">\n              <label>\n                Morgen fra\n                <input id=\"departFrom\" type=\"time\" />\n              </label>\n              <label>\n                Morgen til\n                <input id=\"departTo\" type=\"time\" />\n              </label>\n              <label>\n                Hjem fra\n                <input id=\"returnFrom\" type=\"time\" />\n              </label>\n              <label>\n                Hjem til\n                <input id=\"returnTo\" type=\"time\" />\n              </label>\n            </div>\n\n            <div class=\"range-row\">\n              <label for=\"leadInput\">Varsl før afgang</label>\n              <input id=\"leadInput\" type=\"range\" min=\"5\" max=\"60\" step=\"5\" />\n              <output id=\"leadOutput\"></output>\n            </div>\n            <div class=\"range-row\">\n              <label for=\"delayInput\">Minimum forsinkelse</label>\n              <input id=\"delayInput\" type=\"range\" min=\"0\" max=\"30\" step=\"1\" />\n              <output id=\"delayOutput\"></output>\n            </div>\n\n            <div class=\"channel-row\">\n              <label class=\"switch\">\n                <input id=\"pushChannel\" type=\"checkbox\" />\n                <span></span>\n                Push\n              </label>\n              <label class=\"switch\">\n                <input id=\"emailChannel\" type=\"checkbox\" />\n                <span></span>\n                Mail\n              </label>\n            </div>\n\n            <button class=\"button primary full\" type=\"submit\">Gem ændringer</button>\n          </form>\n        </section>\n\n        <section class=\"panel map-panel\" aria-labelledby=\"mapTitle\">\n          <div class=\"panel-heading map-heading\">\n            <div>\n              <p class=\"eyebrow\">Kort</p>\n              <h2 id=\"mapTitle\">Tegn eller foreslå ruten</h2>\n            </div>\n            <div class=\"map-actions\">\n              <button class=\"button secondary\" id=\"sampleRoute\" type=\"button\">\n                <svg><use href=\"#icon-route\"></use></svg>\n                Foreslå rute\n              </button>\n              <button class=\"button secondary\" id=\"drawToggle\" type=\"button\" aria-pressed=\"true\">\n                <svg><use href=\"#icon-pen\"></use></svg>\n                Tegn\n              </button>\n              <button class=\"icon-button\" id=\"clearRoute\" type=\"button\" aria-label=\"Ryd rute\" title=\"Ryd rute\">\n                <svg><use href=\"#icon-trash\"></use></svg>\n              </button>\n            </div>\n          </div>\n\n          <div class=\"map-frame\">\n            <div id=\"routeMap\" role=\"application\" aria-label=\"OpenStreetMap-kort til at plotte pendlerute\"></div>\n            <div class=\"map-help\" id=\"mapHelp\">Klik på kortet for at sætte rutepunkter. Appen forsøger at finde vejnavnet for hvert punkt.</div>\n          </div>\n        </section>\n\n        <section class=\"panel monitor-panel\" aria-labelledby=\"monitorTitle\">\n          <div class=\"panel-heading\">\n            <div>\n              <p class=\"eyebrow\">Overvågning</p>\n              <h2 id=\"monitorTitle\">Alarmstatus</h2>\n            </div>\n            <button class=\"button primary\" id=\"runCheck\" type=\"button\">\n              <svg><use href=\"#icon-play\"></use></svg>\n              Kør tjek\n            </button>\n          </div>\n\n          <div class=\"status-tile\" id=\"nextTripTile\">\n            <span>Næste tjek</span>\n            <strong>Ikke beregnet endnu</strong>\n          </div>\n\n          <div class=\"info-block\">\n            <div class=\"info-heading\">\n              <h3>Genkendte veje</h3>\n              <span id=\"segmentCount\">0</span>\n            </div>\n            <div class=\"chips\" id=\"roadChips\"></div>\n          </div>\n\n          <div class=\"info-block\">\n            <div class=\"info-heading\">\n              <h3>Aktuelle hændelser</h3>\n              <span id=\"matchCount\">0</span>\n            </div>\n            <div class=\"event-list\" id=\"eventList\"></div>\n          </div>\n\n          <div class=\"info-block\">\n            <div class=\"info-heading\">\n              <h3>Beskeder</h3>\n              <button class=\"text-button\" id=\"clearInbox\" type=\"button\">Ryd</button>\n            </div>\n            <div class=\"inbox\" id=\"inbox\"></div>\n          </div>\n        </section>\n      </main>\n    </div>\n\n    <div class=\"toast\" id=\"toast\" role=\"status\" aria-live=\"polite\"></div>\n\n    <script src=\"app.js\" defer></script>\n  </body>\n</html>\n","type":"text/html; charset=utf-8"},"/styles.css":{"body":":root {\n  color-scheme: light;\n  --bg: #f4f1e9;\n  --panel: #fffdf8;\n  --panel-strong: #f9f6ee;\n  --ink: #17201f;\n  --muted: #67716f;\n  --line: #d9d2c4;\n  --line-strong: #b9ad98;\n  --teal: #0f766e;\n  --teal-dark: #0b4f4a;\n  --coral: #cc5538;\n  --amber: #b7791f;\n  --green: #2f7d54;\n  --red: #ad2f2f;\n  --road: #dcc9a4;\n  --road-edge: #f1eadc;\n  --shadow: 0 18px 45px rgba(24, 32, 31, 0.12);\n  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  min-height: 100vh;\n  background:\n    linear-gradient(120deg, rgba(15, 118, 110, 0.08), transparent 36%),\n    linear-gradient(255deg, rgba(204, 85, 56, 0.07), transparent 34%),\n    var(--bg);\n  color: var(--ink);\n}\n\nbutton,\ninput {\n  font: inherit;\n}\n\nbutton {\n  cursor: pointer;\n}\n\n.icon-sprite {\n  display: none;\n}\n\n.app-shell {\n  min-height: 100vh;\n  padding: 20px;\n}\n\n.topbar {\n  align-items: center;\n  display: flex;\n  gap: 16px;\n  justify-content: space-between;\n  margin: 0 auto 16px;\n  max-width: 1500px;\n}\n\n.brand {\n  align-items: center;\n  display: flex;\n  gap: 12px;\n}\n\n.brand-mark {\n  align-items: center;\n  background: var(--ink);\n  border-radius: 8px;\n  color: #fffdf8;\n  display: grid;\n  font-size: 17px;\n  font-weight: 800;\n  height: 48px;\n  letter-spacing: 0;\n  place-items: center;\n  width: 48px;\n}\n\n.brand h1,\n.brand p,\n.panel-heading h2,\n.panel-heading p,\n.info-heading h3 {\n  margin: 0;\n}\n\n.brand h1 {\n  font-size: 23px;\n  line-height: 1.1;\n}\n\n.brand p {\n  color: var(--muted);\n  margin-top: 3px;\n}\n\n.topbar-actions {\n  align-items: center;\n  display: flex;\n  gap: 10px;\n}\n\n.system-status {\n  background: rgba(47, 125, 84, 0.12);\n  border: 1px solid rgba(47, 125, 84, 0.25);\n  border-radius: 8px;\n  color: #24583d;\n  font-size: 14px;\n  padding: 10px 12px;\n  white-space: nowrap;\n}\n\n.workspace {\n  display: grid;\n  gap: 16px;\n  grid-template-columns: minmax(270px, 340px) minmax(420px, 1fr) minmax(300px, 380px);\n  margin: 0 auto;\n  max-width: 1500px;\n}\n\n.auth-banner {\n  align-items: center;\n  background: #17312f;\n  border-radius: 8px;\n  color: #fffdf8;\n  display: none;\n  gap: 16px;\n  grid-column: 1 / -1;\n  justify-content: space-between;\n  padding: 14px;\n}\n\n.auth-banner.show {\n  display: flex;\n}\n\n.auth-banner strong {\n  display: block;\n  font-size: 16px;\n}\n\n.auth-banner span {\n  color: rgba(255, 253, 248, 0.78);\n  display: block;\n  font-size: 14px;\n  margin-top: 2px;\n}\n\n.quick-profile {\n  align-items: end;\n  display: grid;\n  gap: 10px;\n  grid-template-columns: minmax(150px, 210px) minmax(180px, 260px) auto;\n}\n\n.quick-profile label {\n  color: rgba(255, 253, 248, 0.82);\n  font-size: 12px;\n}\n\n.quick-profile input {\n  background: rgba(255, 253, 248, 0.95);\n  border-color: transparent;\n  margin-top: 4px;\n}\n\n.panel {\n  background: var(--panel);\n  border: 1px solid rgba(185, 173, 152, 0.55);\n  border-radius: 8px;\n  box-shadow: var(--shadow);\n  min-width: 0;\n  padding: 16px;\n}\n\n.panel-heading {\n  align-items: center;\n  display: flex;\n  gap: 12px;\n  justify-content: space-between;\n  margin-bottom: 16px;\n}\n\n.panel-heading h2 {\n  font-size: 19px;\n  line-height: 1.2;\n}\n\n.eyebrow {\n  color: var(--teal-dark);\n  font-size: 12px;\n  font-weight: 800;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n}\n\n.panel-icon {\n  color: var(--teal);\n  height: 24px;\n  width: 24px;\n}\n\n.form-stack {\n  display: grid;\n  gap: 14px;\n}\n\nlabel {\n  color: var(--muted);\n  display: grid;\n  font-size: 13px;\n  gap: 6px;\n}\n\ninput {\n  background: #fff;\n  border: 1px solid var(--line);\n  border-radius: 7px;\n  color: var(--ink);\n  min-height: 40px;\n  outline: none;\n  padding: 9px 10px;\n  width: 100%;\n}\n\ninput:focus {\n  border-color: var(--teal);\n  box-shadow: 0 0 0 3px rgba(15, 118, 110, 0.14);\n}\n\n.field-grid,\n.time-grid {\n  display: grid;\n  gap: 10px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.section-label {\n  color: var(--ink);\n  font-size: 13px;\n  font-weight: 800;\n  margin-bottom: -6px;\n}\n\n.segmented {\n  background: var(--panel-strong);\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  display: grid;\n  grid-template-columns: repeat(2, 1fr);\n  padding: 3px;\n}\n\n.segment {\n  background: transparent;\n  border: 0;\n  border-radius: 6px;\n  color: var(--muted);\n  min-height: 36px;\n}\n\n.segment.active {\n  background: var(--ink);\n  color: #fffdf8;\n  font-weight: 750;\n}\n\n.days {\n  display: grid;\n  gap: 7px;\n  grid-template-columns: repeat(4, 1fr);\n}\n\n.days label {\n  align-items: center;\n  background: var(--panel-strong);\n  border: 1px solid var(--line);\n  border-radius: 7px;\n  color: var(--ink);\n  display: flex;\n  font-size: 13px;\n  gap: 6px;\n  justify-content: center;\n  min-height: 34px;\n}\n\n.days input {\n  height: 15px;\n  min-height: 15px;\n  width: 15px;\n}\n\n.range-row {\n  align-items: center;\n  display: grid;\n  gap: 9px;\n  grid-template-columns: 1fr 1.3fr 52px;\n}\n\n.range-row label {\n  color: var(--ink);\n  font-weight: 750;\n}\n\ninput[type=\"range\"] {\n  accent-color: var(--teal);\n  border: 0;\n  padding: 0;\n}\n\noutput {\n  color: var(--muted);\n  font-size: 13px;\n  text-align: right;\n}\n\n.channel-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n}\n\n.switch {\n  align-items: center;\n  background: var(--panel-strong);\n  border: 1px solid var(--line);\n  border-radius: 7px;\n  color: var(--ink);\n  display: flex;\n  font-size: 14px;\n  gap: 9px;\n  min-height: 40px;\n  padding: 8px 10px;\n}\n\n.switch input {\n  display: none;\n}\n\n.switch span {\n  background: var(--line-strong);\n  border-radius: 99px;\n  display: inline-block;\n  height: 20px;\n  position: relative;\n  transition: background 160ms ease;\n  width: 36px;\n}\n\n.switch span::after {\n  background: #fff;\n  border-radius: 50%;\n  content: \"\";\n  height: 16px;\n  left: 2px;\n  position: absolute;\n  top: 2px;\n  transition: transform 160ms ease;\n  width: 16px;\n}\n\n.switch input:checked + span {\n  background: var(--teal);\n}\n\n.switch input:checked + span::after {\n  transform: translateX(16px);\n}\n\n.button,\n.icon-button,\n.text-button {\n  align-items: center;\n  border: 0;\n  border-radius: 7px;\n  display: inline-flex;\n  font-weight: 750;\n  gap: 7px;\n  justify-content: center;\n  min-height: 40px;\n  padding: 9px 12px;\n}\n\n.button svg,\n.icon-button svg,\n.panel-icon {\n  fill: none;\n  stroke: currentColor;\n  stroke-linecap: round;\n  stroke-linejoin: round;\n  stroke-width: 2;\n}\n\n.button svg {\n  height: 18px;\n  width: 18px;\n}\n\n.button.primary {\n  background: var(--teal);\n  color: #fff;\n}\n\n.button.primary:hover {\n  background: var(--teal-dark);\n}\n\n.button.secondary {\n  background: #ece7dc;\n  color: var(--ink);\n}\n\n.button.secondary:hover {\n  background: #e0d8c9;\n}\n\n.button.full {\n  width: 100%;\n}\n\n.icon-button {\n  background: #f1e9de;\n  color: var(--ink);\n  flex: 0 0 auto;\n  padding: 9px;\n  width: 40px;\n}\n\n.icon-button svg {\n  height: 18px;\n  width: 18px;\n}\n\n.text-button {\n  background: transparent;\n  color: var(--teal-dark);\n  min-height: 30px;\n  padding: 4px 0;\n}\n\n.map-panel {\n  display: grid;\n  grid-template-rows: auto minmax(480px, 1fr);\n  min-height: 650px;\n}\n\n.map-heading {\n  align-items: start;\n}\n\n.map-actions {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n  justify-content: flex-end;\n}\n\n.map-frame {\n  background: #efe9dd;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  min-height: 0;\n  overflow: hidden;\n  position: relative;\n}\n\n#routeMap {\n  background: #e8e1d4;\n  cursor: crosshair;\n  height: 100%;\n  min-height: 500px;\n  overflow: hidden;\n  position: relative;\n  touch-action: none;\n  user-select: none;\n  width: 100%;\n}\n\n#routeMap.is-dragging {\n  cursor: grabbing;\n}\n\n#routeMap:focus {\n  outline: 3px solid rgba(15, 118, 110, 0.25);\n  outline-offset: -3px;\n}\n\n.map-tile-layer,\n.map-overlay,\n.map-controls,\n.map-attribution {\n  position: absolute;\n}\n\n.map-tile-layer {\n  inset: 0;\n}\n\n.map-tile {\n  height: 256px;\n  position: absolute;\n  width: 256px;\n}\n\n.map-overlay {\n  inset: 0;\n  pointer-events: none;\n}\n\n.map-overlay .route-path {\n  fill: none;\n  stroke: var(--teal);\n  stroke-linecap: round;\n  stroke-linejoin: round;\n  stroke-width: 7;\n}\n\n.map-overlay .route-halo {\n  fill: none;\n  stroke: rgba(23, 32, 31, 0.22);\n  stroke-linecap: round;\n  stroke-linejoin: round;\n  stroke-width: 12;\n}\n\n.map-overlay .route-point-svg {\n  fill: #fffdf8;\n  stroke: var(--teal-dark);\n  stroke-width: 4;\n}\n\n.map-overlay .route-number {\n  fill: var(--teal-dark);\n  font-size: 12px;\n  font-weight: 900;\n  text-anchor: middle;\n}\n\n.map-overlay .event-point {\n  fill: #fffdf8;\n  stroke: var(--amber);\n  stroke-width: 4;\n}\n\n.map-overlay .event-point.high {\n  stroke: var(--red);\n}\n\n.map-overlay .event-point.low {\n  stroke: var(--green);\n}\n\n.map-overlay .event-label {\n  fill: var(--ink);\n  font-size: 18px;\n  font-weight: 900;\n  text-anchor: middle;\n}\n\n.map-controls {\n  align-items: start;\n  display: flex;\n  gap: 8px;\n  left: 12px;\n  top: 12px;\n  z-index: 2;\n}\n\n.zoom-controls {\n  display: grid;\n  gap: 5px;\n}\n\n.pan-controls {\n  display: grid;\n  gap: 4px;\n  grid-template-columns: repeat(3, 30px);\n}\n\n.pan-controls [data-pan=\"north\"] {\n  grid-column: 2;\n  grid-row: 1;\n}\n\n.pan-controls [data-pan=\"west\"] {\n  grid-column: 1;\n  grid-row: 2;\n}\n\n.pan-controls [data-pan=\"east\"] {\n  grid-column: 3;\n  grid-row: 2;\n}\n\n.pan-controls [data-pan=\"south\"] {\n  grid-column: 2;\n  grid-row: 3;\n}\n\n.map-controls button {\n  align-items: center;\n  background: #fffdf8;\n  border: 1px solid rgba(185, 173, 152, 0.75);\n  border-radius: 7px;\n  box-shadow: 0 5px 14px rgba(23, 32, 31, 0.15);\n  color: var(--ink);\n  display: flex;\n  font-size: 18px;\n  font-weight: 850;\n  height: 32px;\n  justify-content: center;\n  padding: 0;\n  width: 32px;\n}\n\n.map-attribution {\n  background: rgba(255, 253, 248, 0.9);\n  bottom: 0;\n  color: var(--muted);\n  font-size: 11px;\n  padding: 3px 6px;\n  right: 0;\n  z-index: 2;\n}\n\n.map-attribution a {\n  color: var(--teal-dark);\n}\n\n.route-point-marker {\n  align-items: center;\n  background: #fffdf8;\n  border: 3px solid var(--teal-dark);\n  border-radius: 50%;\n  box-shadow: 0 2px 8px rgba(23, 32, 31, 0.25);\n  color: var(--teal-dark);\n  display: flex;\n  font-size: 12px;\n  font-weight: 900;\n  height: 25px;\n  justify-content: center;\n  width: 25px;\n}\n\n.traffic-event-marker {\n  align-items: center;\n  background: #fffdf8;\n  border: 4px solid var(--amber);\n  border-radius: 50%;\n  box-shadow: 0 3px 12px rgba(23, 32, 31, 0.25);\n  color: var(--ink);\n  display: flex;\n  font-size: 16px;\n  font-weight: 900;\n  height: 30px;\n  justify-content: center;\n  width: 30px;\n}\n\n.traffic-event-marker.high {\n  border-color: var(--red);\n}\n\n.traffic-event-marker.low {\n  border-color: var(--green);\n}\n\n.map-help {\n  background: rgba(255, 253, 248, 0.92);\n  border: 1px solid rgba(185, 173, 152, 0.58);\n  border-radius: 7px;\n  bottom: 12px;\n  color: var(--muted);\n  font-size: 13px;\n  left: 12px;\n  max-width: min(540px, calc(100% - 24px));\n  padding: 9px 10px;\n  position: absolute;\n}\n\n.monitor-panel {\n  display: grid;\n  gap: 14px;\n  grid-auto-rows: max-content;\n}\n\n.status-tile {\n  background: #17312f;\n  border-radius: 8px;\n  color: #fffdf8;\n  display: grid;\n  gap: 5px;\n  padding: 14px;\n}\n\n.status-tile span {\n  color: rgba(255, 253, 248, 0.7);\n  font-size: 12px;\n  font-weight: 800;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n}\n\n.status-tile strong {\n  font-size: 18px;\n  line-height: 1.25;\n}\n\n.info-block {\n  border-top: 1px solid var(--line);\n  padding-top: 14px;\n}\n\n.info-heading {\n  align-items: center;\n  display: flex;\n  justify-content: space-between;\n  margin-bottom: 10px;\n}\n\n.info-heading h3 {\n  font-size: 15px;\n}\n\n.info-heading span {\n  background: var(--panel-strong);\n  border: 1px solid var(--line);\n  border-radius: 999px;\n  color: var(--muted);\n  font-size: 12px;\n  font-weight: 800;\n  min-width: 26px;\n  padding: 3px 8px;\n  text-align: center;\n}\n\n.chips,\n.event-list,\n.inbox {\n  display: grid;\n  gap: 8px;\n}\n\n.chip {\n  align-items: center;\n  background: #f2ece1;\n  border: 1px solid var(--line);\n  border-radius: 999px;\n  color: var(--ink);\n  display: inline-flex;\n  font-size: 13px;\n  font-weight: 700;\n  min-height: 30px;\n  padding: 6px 10px;\n  width: fit-content;\n}\n\n.empty {\n  color: var(--muted);\n  font-size: 14px;\n  line-height: 1.45;\n}\n\n.event-item,\n.message-item {\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  display: grid;\n  gap: 5px;\n  padding: 10px;\n}\n\n.event-item {\n  background: #fffaf0;\n}\n\n.event-item.high {\n  border-left: 5px solid var(--red);\n}\n\n.event-item.medium {\n  border-left: 5px solid var(--amber);\n}\n\n.event-item.low {\n  border-left: 5px solid var(--green);\n}\n\n.event-title,\n.message-title {\n  align-items: center;\n  display: flex;\n  gap: 7px;\n  justify-content: space-between;\n}\n\n.event-title strong,\n.message-title strong {\n  font-size: 14px;\n}\n\n.badge {\n  border-radius: 999px;\n  color: #fff;\n  font-size: 11px;\n  font-weight: 850;\n  padding: 3px 7px;\n  white-space: nowrap;\n}\n\n.badge.high {\n  background: var(--red);\n}\n\n.badge.medium {\n  background: var(--amber);\n}\n\n.badge.low {\n  background: var(--green);\n}\n\n.event-meta,\n.message-meta {\n  color: var(--muted);\n  font-size: 12px;\n  line-height: 1.4;\n}\n\n.message-item {\n  background: #f7f3ea;\n}\n\n.message-item svg {\n  color: var(--teal);\n  fill: none;\n  height: 16px;\n  stroke: currentColor;\n  stroke-linecap: round;\n  stroke-linejoin: round;\n  stroke-width: 2;\n  width: 16px;\n}\n\n.toast {\n  background: var(--ink);\n  border-radius: 8px;\n  bottom: 22px;\n  color: #fffdf8;\n  left: 50%;\n  max-width: min(420px, calc(100% - 32px));\n  opacity: 0;\n  padding: 11px 14px;\n  pointer-events: none;\n  position: fixed;\n  transform: translate(-50%, 16px);\n  transition: opacity 180ms ease, transform 180ms ease;\n  z-index: 10;\n}\n\n.toast.show {\n  opacity: 1;\n  transform: translate(-50%, 0);\n}\n\n@media (max-width: 1180px) {\n  .workspace {\n    grid-template-columns: minmax(280px, 360px) 1fr;\n  }\n\n  .monitor-panel {\n    grid-column: 1 / -1;\n  }\n}\n\n@media (max-width: 820px) {\n  .app-shell {\n    padding: 12px;\n  }\n\n  .topbar,\n  .auth-banner {\n    align-items: stretch;\n    flex-direction: column;\n  }\n\n  .topbar-actions,\n  .quick-profile {\n    align-items: stretch;\n    grid-template-columns: 1fr;\n  }\n\n  .topbar-actions {\n    display: grid;\n  }\n\n  .workspace {\n    grid-template-columns: 1fr;\n  }\n\n  .field-grid,\n  .time-grid,\n  .range-row {\n    grid-template-columns: 1fr;\n  }\n\n  output {\n    text-align: left;\n  }\n\n  .days {\n    grid-template-columns: repeat(3, 1fr);\n  }\n\n  .map-panel {\n    min-height: 560px;\n  }\n\n  #routeMap {\n    min-height: 450px;\n  }\n\n  .map-heading {\n    align-items: stretch;\n    flex-direction: column;\n  }\n\n  .map-actions {\n    justify-content: stretch;\n  }\n\n  .map-actions .button {\n    flex: 1 1 auto;\n  }\n}\n","type":"text/css; charset=utf-8"},"/app.js":{"body":"const STORAGE_KEY = \"trafikalarm.prototype.v3\";\nconst COPENHAGEN_CENTER = { lat: 55.6761, lng: 12.5683 };\nconst TILE_URL = \"https://tile.openstreetmap.org/{z}/{x}/{y}.png\";\nconst NOMINATIM_URL = \"https://nominatim.openstreetmap.org/reverse\";\nconst SVG_NS = \"http://www.w3.org/2000/svg\";\nconst TILE_SIZE = 256;\nconst MIN_ZOOM = 10;\nconst MAX_ZOOM = 18;\n\nconst roadNameCache = new Map();\n\nconst simulatedEvents = [\n  {\n    id: \"event-borups-crash\",\n    lat: 55.69423,\n    lng: 12.53556,\n    roadName: \"Borups Alle\",\n    type: \"Uheld\",\n    severity: \"high\",\n    delay: 18,\n    title: \"Uheld blokerer højre spor\",\n    window: \"07:05-09:20\",\n    source: \"Vejdirektoratet\",\n    radiusMeters: 550,\n  },\n  {\n    id: \"event-tagens-roadwork\",\n    lat: 55.70545,\n    lng: 12.55021,\n    roadName: \"Tagensvej\",\n    type: \"Vejarbejde\",\n    severity: \"medium\",\n    delay: 9,\n    title: \"Akut vejarbejde ved kryds\",\n    window: \"06:30-10:00\",\n    source: \"Dataudveksleren\",\n    radiusMeters: 450,\n  },\n  {\n    id: \"event-strandboulevard-queue\",\n    lat: 55.70483,\n    lng: 12.58794,\n    roadName: \"Strandboulevarden\",\n    type: \"Kø\",\n    severity: \"medium\",\n    delay: 12,\n    title: \"Langsom trafik mod Nordhavn\",\n    window: \"15:00-18:30\",\n    source: \"DR Trafik\",\n    radiusMeters: 450,\n  },\n  {\n    id: \"event-amager-closure\",\n    lat: 55.63874,\n    lng: 12.58292,\n    roadName: \"Amagermotorvejen\",\n    type: \"Spor lukket\",\n    severity: \"high\",\n    delay: 24,\n    title: \"Et spor lukket efter tabt gods\",\n    window: \"07:30-08:50\",\n    source: \"Vejdirektoratet\",\n    radiusMeters: 700,\n  },\n  {\n    id: \"event-roskilde-slow\",\n    lat: 55.67251,\n    lng: 12.50633,\n    roadName: \"Roskildevej\",\n    type: \"Langsom trafik\",\n    severity: \"low\",\n    delay: 5,\n    title: \"Tæt trafik mod byen\",\n    window: \"07:00-09:00\",\n    source: \"Trafikinfo\",\n    radiusMeters: 420,\n  },\n];\n\nconst sampleRoutes = {\n  work: [\n    { lat: 55.68888, lng: 12.49193, roadName: \"Jyllingevej\" },\n    { lat: 55.6931, lng: 12.51457, roadName: \"Borups Alle\" },\n    { lat: 55.69508, lng: 12.53656, roadName: \"Borups Alle\" },\n    { lat: 55.70442, lng: 12.54968, roadName: \"Tagensvej\" },\n    { lat: 55.71062, lng: 12.56161, roadName: \"Lyngbyvej\" },\n    { lat: 55.70754, lng: 12.58981, roadName: \"Strandboulevarden\" },\n  ],\n  home: [\n    { lat: 55.70754, lng: 12.58981, roadName: \"Strandboulevarden\" },\n    { lat: 55.70442, lng: 12.54968, roadName: \"Tagensvej\" },\n    { lat: 55.69508, lng: 12.53656, roadName: \"Borups Alle\" },\n    { lat: 55.6917, lng: 12.52091, roadName: \"Hulgårdsvej\" },\n    { lat: 55.68888, lng: 12.49193, roadName: \"Jyllingevej\" },\n  ],\n};\n\nconst defaultState = {\n  user: {\n    name: \"\",\n    email: \"\",\n    home: \"Vanløse\",\n    work: \"Nordhavn\",\n    homeLocation: null,\n    workLocation: null,\n  },\n  routeMode: \"work\",\n  drawMode: true,\n  schedule: {\n    days: [\"mon\", \"tue\", \"wed\", \"thu\", \"fri\"],\n    departFrom: \"07:15\",\n    departTo: \"08:45\",\n    returnFrom: \"15:30\",\n    returnTo: \"17:30\",\n    lead: 25,\n    minDelay: 8,\n    channels: {\n      push: true,\n      email: true,\n    },\n  },\n  routes: {\n    work: {\n      points: [],\n    },\n    home: {\n      points: [],\n    },\n  },\n  inbox: [],\n  lastMatches: [],\n  lastCheck: null,\n};\n\nlet state = sanitizeState(loadState());\nlet mapState = null;\nconst addressLookupTimer = {\n  home: null,\n  work: null,\n};\nconst addressSuggestions = {\n  home: [],\n  work: [],\n};\n\nconst elements = {\n  authBanner: document.querySelector(\"#authBanner\"),\n  quickProfileForm: document.querySelector(\"#quickProfileForm\"),\n  quickName: document.querySelector(\"#quickName\"),\n  quickEmail: document.querySelector(\"#quickEmail\"),\n  profileForm: document.querySelector(\"#profileForm\"),\n  nameInput: document.querySelector(\"#nameInput\"),\n  emailInput: document.querySelector(\"#emailInput\"),\n  homeInput: document.querySelector(\"#homeInput\"),\n  workInput: document.querySelector(\"#workInput\"),\n  homeSuggestions: document.querySelector(\"#homeSuggestions\"),\n  workSuggestions: document.querySelector(\"#workSuggestions\"),\n  daysGroup: document.querySelector(\"#daysGroup\"),\n  departFrom: document.querySelector(\"#departFrom\"),\n  departTo: document.querySelector(\"#departTo\"),\n  returnFrom: document.querySelector(\"#returnFrom\"),\n  returnTo: document.querySelector(\"#returnTo\"),\n  leadInput: document.querySelector(\"#leadInput\"),\n  leadOutput: document.querySelector(\"#leadOutput\"),\n  delayInput: document.querySelector(\"#delayInput\"),\n  delayOutput: document.querySelector(\"#delayOutput\"),\n  pushChannel: document.querySelector(\"#pushChannel\"),\n  emailChannel: document.querySelector(\"#emailChannel\"),\n  modeButtons: document.querySelectorAll(\".segment[data-mode]\"),\n  sampleRoute: document.querySelector(\"#sampleRoute\"),\n  drawToggle: document.querySelector(\"#drawToggle\"),\n  clearRoute: document.querySelector(\"#clearRoute\"),\n  requestNotifications: document.querySelector(\"#requestNotifications\"),\n  runCheck: document.querySelector(\"#runCheck\"),\n  clearInbox: document.querySelector(\"#clearInbox\"),\n  routeMap: document.querySelector(\"#routeMap\"),\n  mapHelp: document.querySelector(\"#mapHelp\"),\n  roadChips: document.querySelector(\"#roadChips\"),\n  segmentCount: document.querySelector(\"#segmentCount\"),\n  eventList: document.querySelector(\"#eventList\"),\n  matchCount: document.querySelector(\"#matchCount\"),\n  inbox: document.querySelector(\"#inbox\"),\n  nextTripTile: document.querySelector(\"#nextTripTile\"),\n  systemStatus: document.querySelector(\"#systemStatus\"),\n  toast: document.querySelector(\"#toast\"),\n};\n\ninit();\n\nfunction init() {\n  initMap();\n  bindEvents();\n  syncForm();\n  renderAll();\n  registerServiceWorker();\n}\n\nfunction loadState() {\n  try {\n    const raw = localStorage.getItem(STORAGE_KEY);\n    if (!raw) return structuredClone(defaultState);\n    return mergeState(structuredClone(defaultState), JSON.parse(raw));\n  } catch {\n    return structuredClone(defaultState);\n  }\n}\n\nfunction mergeState(base, saved) {\n  return {\n    ...base,\n    ...saved,\n    user: { ...base.user, ...(saved.user || {}) },\n    schedule: {\n      ...base.schedule,\n      ...(saved.schedule || {}),\n      channels: {\n        ...base.schedule.channels,\n        ...((saved.schedule && saved.schedule.channels) || {}),\n      },\n    },\n    routes: {\n      work: { ...base.routes.work, ...((saved.routes && saved.routes.work) || {}) },\n      home: { ...base.routes.home, ...((saved.routes && saved.routes.home) || {}) },\n    },\n  };\n}\n\nfunction sanitizeState(nextState) {\n  nextState.user.homeLocation = sanitizeLocation(nextState.user.homeLocation);\n  nextState.user.workLocation = sanitizeLocation(nextState.user.workLocation);\n\n  [\"work\", \"home\"].forEach((mode) => {\n    nextState.routes[mode].points = (nextState.routes[mode].points || [])\n      .filter((point) => Number.isFinite(point.lat) && Number.isFinite(point.lng))\n      .map((point) => ({\n        lat: roundCoord(point.lat),\n        lng: roundCoord(point.lng),\n        roadName: point.roadName || \"Ukendt vej\",\n      }));\n  });\n  return nextState;\n}\n\nfunction sanitizeLocation(location) {\n  if (!location || !Number.isFinite(location.lat) || !Number.isFinite(location.lng)) return null;\n  return {\n    label: location.label || \"\",\n    roadName: location.roadName || location.label || \"Ukendt vej\",\n    lat: roundCoord(location.lat),\n    lng: roundCoord(location.lng),\n  };\n}\n\nfunction saveState() {\n  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));\n}\n\nfunction initMap() {\n  const tileLayer = document.createElement(\"div\");\n  tileLayer.className = \"map-tile-layer\";\n\n  const overlay = document.createElementNS(SVG_NS, \"svg\");\n  overlay.classList.add(\"map-overlay\");\n\n  const controls = document.createElement(\"div\");\n  controls.className = \"map-controls\";\n  controls.innerHTML = `\n    <div class=\"zoom-controls\" aria-label=\"Zoom\">\n      <button type=\"button\" data-zoom=\"in\" aria-label=\"Zoom ind\">+</button>\n      <button type=\"button\" data-zoom=\"out\" aria-label=\"Zoom ud\">-</button>\n    </div>\n    <div class=\"pan-controls\" aria-label=\"Flyt kort\">\n      <button type=\"button\" data-pan=\"north\" aria-label=\"Flyt kort op\">↑</button>\n      <button type=\"button\" data-pan=\"west\" aria-label=\"Flyt kort til venstre\">←</button>\n      <button type=\"button\" data-pan=\"east\" aria-label=\"Flyt kort til højre\">→</button>\n      <button type=\"button\" data-pan=\"south\" aria-label=\"Flyt kort ned\">↓</button>\n    </div>\n  `;\n\n  const attribution = document.createElement(\"div\");\n  attribution.className = \"map-attribution\";\n  attribution.innerHTML = `&copy; <a href=\"https://www.openstreetmap.org/copyright\" target=\"_blank\" rel=\"noreferrer\">OpenStreetMap</a>-bidragsydere`;\n\n  elements.routeMap.textContent = \"\";\n  elements.routeMap.tabIndex = 0;\n  elements.routeMap.append(tileLayer, overlay, controls, attribution);\n\n  mapState = {\n    center: { ...COPENHAGEN_CENTER },\n    zoom: 12,\n    tileLayer,\n    overlay,\n    pointerDown: false,\n    isDragging: false,\n    startPointer: null,\n    startCenterWorld: null,\n    renderFrame: null,\n    wheelDelta: 0,\n    wheelResetTimer: null,\n    lastWheelZoom: 0,\n  };\n\n  controls.addEventListener(\"click\", (event) => {\n    const button = event.target.closest(\"button[data-zoom]\");\n    const panButton = event.target.closest(\"button[data-pan]\");\n    if (!button && !panButton) return;\n    event.stopPropagation();\n    if (button) {\n      setZoom(mapState.zoom + (button.dataset.zoom === \"in\" ? 1 : -1));\n    } else {\n      panMap(panButton.dataset.pan);\n    }\n  });\n\n  elements.routeMap.addEventListener(\"pointerdown\", handleMapPointerDown);\n  elements.routeMap.addEventListener(\"contextmenu\", handleMapContextMenu);\n  elements.routeMap.addEventListener(\"keydown\", handleMapKeyDown);\n  window.addEventListener(\"pointermove\", handleMapPointerMove);\n  window.addEventListener(\"pointerup\", handleMapPointerUp);\n  elements.routeMap.addEventListener(\"wheel\", handleMapWheel, { passive: false });\n\n  new ResizeObserver(renderMap).observe(elements.routeMap);\n  renderMap();\n}\n\nfunction bindEvents() {\n  elements.quickProfileForm.addEventListener(\"submit\", (event) => {\n    event.preventDefault();\n    state.user.name = elements.quickName.value.trim();\n    state.user.email = elements.quickEmail.value.trim();\n    syncForm();\n    renderAll();\n    saveState();\n    showToast(\"Profilen er gemt lokalt.\");\n  });\n\n  elements.profileForm.addEventListener(\"submit\", (event) => {\n    event.preventDefault();\n    readForm();\n    renderAll();\n    saveState();\n    showToast(\"Ændringerne er gemt.\");\n  });\n\n  elements.homeInput.addEventListener(\"input\", () => handleAddressInput(\"home\"));\n  elements.workInput.addEventListener(\"input\", () => handleAddressInput(\"work\"));\n  elements.homeInput.addEventListener(\"change\", () => applySelectedAddress(\"home\"));\n  elements.workInput.addEventListener(\"change\", () => applySelectedAddress(\"work\"));\n\n  elements.modeButtons.forEach((button) => {\n    button.addEventListener(\"click\", () => {\n      state.routeMode = button.dataset.mode;\n      renderAll();\n      fitActiveRoute();\n      saveState();\n    });\n  });\n\n  elements.daysGroup.querySelectorAll(\"input\").forEach((input) => {\n    input.addEventListener(\"change\", () => {\n      readForm();\n      renderAll();\n      saveState();\n    });\n  });\n\n  [\n    elements.departFrom,\n    elements.departTo,\n    elements.returnFrom,\n    elements.returnTo,\n    elements.leadInput,\n    elements.delayInput,\n    elements.pushChannel,\n    elements.emailChannel,\n  ].forEach((input) => {\n    input.addEventListener(\"input\", () => {\n      readForm();\n      renderAll();\n      saveState();\n    });\n  });\n\n  elements.sampleRoute.addEventListener(\"click\", () => {\n    setSampleRoute(state.routeMode);\n    state.lastMatches = [];\n    renderAll();\n    fitActiveRoute();\n    saveState();\n    showToast(\"Ruten er foreslået på OpenStreetMap og klar til redigering.\");\n  });\n\n  elements.drawToggle.addEventListener(\"click\", () => {\n    state.drawMode = !state.drawMode;\n    renderAll();\n    saveState();\n  });\n\n  elements.clearRoute.addEventListener(\"click\", () => {\n    getActiveRoute().points = [];\n    state.lastMatches = [];\n    renderAll();\n    saveState();\n    showToast(\"Ruten er ryddet.\");\n  });\n\n  elements.runCheck.addEventListener(\"click\", () => {\n    readForm();\n    runTrafficCheck();\n  });\n\n  elements.requestNotifications.addEventListener(\"click\", requestNotifications);\n\n  elements.clearInbox.addEventListener(\"click\", () => {\n    state.inbox = [];\n    saveState();\n    renderInbox();\n  });\n}\n\nfunction syncForm() {\n  elements.nameInput.value = state.user.name;\n  elements.emailInput.value = state.user.email;\n  elements.homeInput.value = state.user.home;\n  elements.workInput.value = state.user.work;\n  elements.quickName.value = state.user.name;\n  elements.quickEmail.value = state.user.email;\n  elements.departFrom.value = state.schedule.departFrom;\n  elements.departTo.value = state.schedule.departTo;\n  elements.returnFrom.value = state.schedule.returnFrom;\n  elements.returnTo.value = state.schedule.returnTo;\n  elements.leadInput.value = state.schedule.lead;\n  elements.delayInput.value = state.schedule.minDelay;\n  elements.pushChannel.checked = state.schedule.channels.push;\n  elements.emailChannel.checked = state.schedule.channels.email;\n\n  elements.daysGroup.querySelectorAll(\"input\").forEach((input) => {\n    input.checked = state.schedule.days.includes(input.value);\n  });\n}\n\nfunction readForm() {\n  state.user.name = elements.nameInput.value.trim();\n  state.user.email = elements.emailInput.value.trim();\n  state.user.home = elements.homeInput.value.trim();\n  state.user.work = elements.workInput.value.trim();\n  clearLocationIfTextChanged(\"home\");\n  clearLocationIfTextChanged(\"work\");\n  state.schedule.departFrom = elements.departFrom.value || defaultState.schedule.departFrom;\n  state.schedule.departTo = elements.departTo.value || defaultState.schedule.departTo;\n  state.schedule.returnFrom = elements.returnFrom.value || defaultState.schedule.returnFrom;\n  state.schedule.returnTo = elements.returnTo.value || defaultState.schedule.returnTo;\n  state.schedule.lead = Number(elements.leadInput.value);\n  state.schedule.minDelay = Number(elements.delayInput.value);\n  state.schedule.channels.push = elements.pushChannel.checked;\n  state.schedule.channels.email = elements.emailChannel.checked;\n  state.schedule.days = Array.from(elements.daysGroup.querySelectorAll(\"input:checked\")).map((input) => input.value);\n}\n\nfunction handleAddressInput(kind) {\n  const input = kind === \"home\" ? elements.homeInput : elements.workInput;\n  const value = input.value.trim();\n  state.user[kind] = value;\n  applySelectedAddress(kind, false);\n\n  clearTimeout(addressLookupTimer[kind]);\n  if (value.length < 3) {\n    renderAddressSuggestions(kind, []);\n    return;\n  }\n\n  addressLookupTimer[kind] = setTimeout(async () => {\n    const suggestions = await fetchDawaAddresses(value);\n    addressSuggestions[kind] = suggestions;\n    renderAddressSuggestions(kind, suggestions);\n  }, 260);\n}\n\nfunction applySelectedAddress(kind, shouldToast = true) {\n  const input = kind === \"home\" ? elements.homeInput : elements.workInput;\n  const locationKey = kind === \"home\" ? \"homeLocation\" : \"workLocation\";\n  const selected = addressSuggestions[kind].find((suggestion) => suggestion.label === input.value.trim());\n\n  if (!selected) {\n    clearLocationIfTextChanged(kind);\n    return false;\n  }\n\n  state.user[kind] = selected.label;\n  state.user[locationKey] = {\n    label: selected.label,\n    roadName: selected.roadName,\n    lat: selected.lat,\n    lng: selected.lng,\n  };\n  saveState();\n  if (shouldToast) showToast(`${kind === \"home\" ? \"Hjem\" : \"Arbejde\"} er valgt via DAWA.`);\n  return true;\n}\n\nfunction clearLocationIfTextChanged(kind) {\n  const locationKey = kind === \"home\" ? \"homeLocation\" : \"workLocation\";\n  const input = kind === \"home\" ? elements.homeInput : elements.workInput;\n  const location = state.user[locationKey];\n  if (location && input.value.trim() !== location.label) {\n    state.user[locationKey] = null;\n  }\n}\n\nasync function fetchDawaAddresses(query) {\n  const endpoint = new URL(\"https://api.dataforsyningen.dk/adresser/autocomplete\");\n  endpoint.searchParams.set(\"q\", query);\n  endpoint.searchParams.set(\"per_side\", \"8\");\n  endpoint.searchParams.set(\"type\", \"adresse\");\n  endpoint.searchParams.set(\"srid\", \"4326\");\n\n  try {\n    const response = await fetch(endpoint.toString(), {\n      headers: { Accept: \"application/json\" },\n    });\n    if (!response.ok) throw new Error(\"DAWA lookup failed\");\n    const data = await response.json();\n    return data.map(parseDawaSuggestion).filter(Boolean);\n  } catch {\n    return [];\n  }\n}\n\nfunction parseDawaSuggestion(item) {\n  const address = item.adresse || item.data || {};\n  const lng = Number(address.x ?? address.lon ?? address.lng);\n  const lat = Number(address.y ?? address.lat);\n  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;\n\n  const label = item.tekst || address.betegnelse || address.adressebetegnelse;\n  if (!label) return null;\n\n  return {\n    label,\n    roadName: address.vejnavn || label,\n    lat: roundCoord(lat),\n    lng: roundCoord(lng),\n  };\n}\n\nfunction renderAddressSuggestions(kind, suggestions) {\n  const list = kind === \"home\" ? elements.homeSuggestions : elements.workSuggestions;\n  list.textContent = \"\";\n  suggestions.forEach((suggestion) => {\n    const option = document.createElement(\"option\");\n    option.value = suggestion.label;\n    list.append(option);\n  });\n}\n\nfunction renderAll() {\n  renderMode();\n  renderAuth();\n  renderMap();\n  renderSummary();\n  renderMatches(state.lastMatches || []);\n  renderInbox();\n  renderNextTrip();\n  elements.leadOutput.textContent = `${state.schedule.lead} min`;\n  elements.delayOutput.textContent = `${state.schedule.minDelay} min`;\n  elements.mapHelp.textContent = state.drawMode\n    ? \"Klik for rutepunkt. Højreklik tæt på et punkt for at fjerne det. Piletaster flytter kortet, + og - zoomer.\"\n    : \"Tegning er slået fra. Piletaster flytter kortet, + og - zoomer.\";\n}\n\nfunction renderAuth() {\n  elements.authBanner.classList.toggle(\"show\", !state.user.email);\n}\n\nfunction renderMode() {\n  elements.modeButtons.forEach((button) => {\n    button.classList.toggle(\"active\", button.dataset.mode === state.routeMode);\n  });\n  elements.drawToggle.setAttribute(\"aria-pressed\", String(state.drawMode));\n  elements.drawToggle.classList.toggle(\"primary\", state.drawMode);\n  elements.drawToggle.classList.toggle(\"secondary\", !state.drawMode);\n}\n\nfunction renderMap() {\n  if (!mapState) return;\n\n  renderTiles();\n  renderOverlay();\n}\n\nfunction renderTiles() {\n  const rect = elements.routeMap.getBoundingClientRect();\n  const width = Math.max(1, Math.round(rect.width));\n  const height = Math.max(1, Math.round(rect.height));\n  const centerWorld = latLngToWorld(mapState.center, mapState.zoom);\n  const topLeft = {\n    x: centerWorld.x - width / 2,\n    y: centerWorld.y - height / 2,\n  };\n  const tileStartX = Math.floor(topLeft.x / TILE_SIZE);\n  const tileEndX = Math.floor((topLeft.x + width) / TILE_SIZE);\n  const tileStartY = Math.floor(topLeft.y / TILE_SIZE);\n  const tileEndY = Math.floor((topLeft.y + height) / TILE_SIZE);\n  const tileCount = 2 ** mapState.zoom;\n  const fragment = document.createDocumentFragment();\n\n  for (let x = tileStartX; x <= tileEndX; x += 1) {\n    for (let y = tileStartY; y <= tileEndY; y += 1) {\n      if (y < 0 || y >= tileCount) continue;\n      const wrappedX = ((x % tileCount) + tileCount) % tileCount;\n      const image = document.createElement(\"img\");\n      image.className = \"map-tile\";\n      image.alt = \"\";\n      image.decoding = \"async\";\n      image.draggable = false;\n      image.addEventListener(\"error\", () => image.remove(), { once: true });\n      image.src = TILE_URL\n        .replace(\"{z}\", String(mapState.zoom))\n        .replace(\"{x}\", String(wrappedX))\n        .replace(\"{y}\", String(y));\n      image.style.left = `${Math.round(x * TILE_SIZE - topLeft.x)}px`;\n      image.style.top = `${Math.round(y * TILE_SIZE - topLeft.y)}px`;\n      fragment.append(image);\n    }\n  }\n\n  mapState.tileLayer.replaceChildren(fragment);\n}\n\nfunction renderOverlay() {\n  const rect = elements.routeMap.getBoundingClientRect();\n  const width = Math.max(1, Math.round(rect.width));\n  const height = Math.max(1, Math.round(rect.height));\n  mapState.overlay.setAttribute(\"viewBox\", `0 0 ${width} ${height}`);\n  mapState.overlay.setAttribute(\"width\", String(width));\n  mapState.overlay.setAttribute(\"height\", String(height));\n  mapState.overlay.textContent = \"\";\n\n  const points = getValidRoutePoints().map(latLngToScreen);\n  if (points.length > 1) {\n    const polyline = points.map((point) => `${point.x},${point.y}`).join(\" \");\n    mapState.overlay.append(\n      createSvg(\"polyline\", { class: \"route-halo\", points: polyline }),\n      createSvg(\"polyline\", { class: \"route-path\", points: polyline })\n    );\n  }\n\n  points.forEach((point, index) => {\n    const circle = createSvg(\"circle\", {\n      class: \"route-point-svg\",\n      cx: point.x,\n      cy: point.y,\n      r: index === 0 || index === points.length - 1 ? 12 : 9,\n    });\n    const number = createSvg(\"text\", {\n      class: \"route-number\",\n      x: point.x,\n      y: point.y + 4,\n    });\n    number.textContent = String(index + 1);\n    mapState.overlay.append(circle, number);\n  });\n\n  simulatedEvents.forEach((event) => {\n    const point = latLngToScreen(event);\n    if (point.x < -40 || point.y < -40 || point.x > width + 40 || point.y > height + 40) return;\n\n    const circle = createSvg(\"circle\", {\n      class: `event-point ${event.severity}`,\n      cx: point.x,\n      cy: point.y,\n      r: 14,\n    });\n    const label = createSvg(\"text\", {\n      class: \"event-label\",\n      x: point.x,\n      y: point.y + 6,\n    });\n    label.textContent = \"!\";\n    const title = createSvg(\"title\");\n    title.textContent = `${event.type}: ${event.title} på ${event.roadName}`;\n    circle.append(title);\n    mapState.overlay.append(circle, label);\n  });\n}\n\nfunction renderSummary() {\n  const segments = getRouteSegments();\n  elements.segmentCount.textContent = String(segments.length);\n  elements.roadChips.textContent = \"\";\n\n  if (segments.length === 0) {\n    elements.roadChips.innerHTML = `<div class=\"empty\">Ingen rute endnu. Klik på kortet eller brug Foreslå rute.</div>`;\n    return;\n  }\n\n  segments.forEach((segment) => {\n    const chip = document.createElement(\"span\");\n    chip.className = \"chip\";\n    chip.textContent = segment.name;\n    elements.roadChips.append(chip);\n  });\n}\n\nfunction renderMatches(matches) {\n  elements.matchCount.textContent = String(matches.length);\n  elements.eventList.textContent = \"\";\n\n  if (!matches.length) {\n    elements.eventList.innerHTML = `<div class=\"empty\">Ingen matchende hændelser på den aktive rute.</div>`;\n    return;\n  }\n\n  matches.forEach((event) => {\n    const item = document.createElement(\"article\");\n    item.className = `event-item ${event.severity}`;\n    const distanceText = Number.isFinite(event.distanceMeters)\n      ? ` · ${event.distanceMeters} m fra ruten`\n      : \"\";\n    item.innerHTML = `\n      <div class=\"event-title\">\n        <strong>${event.type}: ${event.roadName}</strong>\n        <span class=\"badge ${event.severity}\">${event.delay} min</span>\n      </div>\n      <div>${event.title}</div>\n      <div class=\"event-meta\">${event.source} · aktiv ${event.window}${distanceText} · matcher din ${routeLabel().toLowerCase()}</div>\n    `;\n    elements.eventList.append(item);\n  });\n}\n\nfunction renderInbox() {\n  elements.inbox.textContent = \"\";\n  if (!state.inbox.length) {\n    elements.inbox.innerHTML = `<div class=\"empty\">Ingen beskeder sendt i prototypen endnu.</div>`;\n    return;\n  }\n\n  state.inbox.slice(0, 6).forEach((message) => {\n    const item = document.createElement(\"article\");\n    item.className = \"message-item\";\n    item.innerHTML = `\n      <div class=\"message-title\">\n        <strong>${message.title}</strong>\n        ${message.channel === \"mail\" ? '<svg><use href=\"#icon-mail\"></use></svg>' : '<svg><use href=\"#icon-bell\"></use></svg>'}\n      </div>\n      <div>${message.body}</div>\n      <div class=\"message-meta\">${message.time} · ${message.channel === \"mail\" ? \"mailkladde\" : \"browser-push\"}</div>\n    `;\n    elements.inbox.append(item);\n  });\n}\n\nfunction renderNextTrip() {\n  const direction = routeLabel();\n  const windowText = state.routeMode === \"work\"\n    ? `${state.schedule.departFrom}-${state.schedule.departTo}`\n    : `${state.schedule.returnFrom}-${state.schedule.returnTo}`;\n  const route = getValidRoutePoints();\n  const pointText = route.length ? `${route.length} rutepunkter` : \"ingen rute\";\n  elements.nextTripTile.innerHTML = `\n    <span>Næste tjek</span>\n    <strong>${direction} · ${windowText}</strong>\n    <small>${state.schedule.lead} min før afgang · ${pointText}</small>\n  `;\n}\n\nfunction handleMapPointerDown(event) {\n  if (event.button !== 0 || event.target.closest(\".map-controls, .map-attribution\")) return;\n  mapState.pointerDown = true;\n  mapState.isDragging = false;\n  mapState.startPointer = { x: event.clientX, y: event.clientY };\n  mapState.startCenterWorld = latLngToWorld(mapState.center, mapState.zoom);\n  elements.routeMap.setPointerCapture(event.pointerId);\n}\n\nfunction handleMapPointerMove(event) {\n  if (!mapState || !mapState.pointerDown) return;\n  const dx = event.clientX - mapState.startPointer.x;\n  const dy = event.clientY - mapState.startPointer.y;\n  if (Math.hypot(dx, dy) < 3) return;\n\n  mapState.isDragging = true;\n  elements.routeMap.classList.add(\"is-dragging\");\n  mapState.center = worldToLatLng(\n    mapState.startCenterWorld.x - dx,\n    mapState.startCenterWorld.y - dy,\n    mapState.zoom\n  );\n  scheduleRenderMap();\n}\n\nfunction handleMapPointerUp(event) {\n  if (!mapState || !mapState.pointerDown) return;\n  const wasDragging = mapState.isDragging;\n  mapState.pointerDown = false;\n  mapState.isDragging = false;\n  elements.routeMap.classList.remove(\"is-dragging\");\n\n  if (!wasDragging && state.drawMode) {\n    const rect = elements.routeMap.getBoundingClientRect();\n    addRoutePoint(screenToLatLng(event.clientX - rect.left, event.clientY - rect.top));\n  }\n}\n\nfunction handleMapContextMenu(event) {\n  event.preventDefault();\n  const rect = elements.routeMap.getBoundingClientRect();\n  const removed = removeNearestRoutePoint(event.clientX - rect.left, event.clientY - rect.top);\n  showToast(removed ? \"Rutepunktet er fjernet.\" : \"Højreklik tættere på et rutepunkt for at fjerne det.\");\n}\n\nfunction handleMapKeyDown(event) {\n  const keyMap = {\n    ArrowUp: \"north\",\n    ArrowRight: \"east\",\n    ArrowDown: \"south\",\n    ArrowLeft: \"west\",\n  };\n\n  if (keyMap[event.key]) {\n    event.preventDefault();\n    panMap(keyMap[event.key]);\n    return;\n  }\n\n  if (event.key === \"+\" || event.key === \"=\") {\n    event.preventDefault();\n    setZoom(mapState.zoom + 1);\n    return;\n  }\n\n  if (event.key === \"-\" || event.key === \"_\") {\n    event.preventDefault();\n    setZoom(mapState.zoom - 1);\n  }\n}\n\nfunction handleMapWheel(event) {\n  event.preventDefault();\n  const now = performance.now();\n  mapState.wheelDelta += event.deltaY;\n  clearTimeout(mapState.wheelResetTimer);\n  mapState.wheelResetTimer = setTimeout(() => {\n    mapState.wheelDelta = 0;\n  }, 220);\n\n  if (Math.abs(mapState.wheelDelta) < 180 || now - mapState.lastWheelZoom < 180) return;\n\n  const direction = mapState.wheelDelta < 0 ? 1 : -1;\n  mapState.wheelDelta = 0;\n  mapState.lastWheelZoom = now;\n  setZoom(mapState.zoom + direction, { x: event.clientX, y: event.clientY });\n}\n\nfunction setZoom(nextZoom, anchorClient = null) {\n  const zoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, nextZoom));\n  if (zoom === mapState.zoom) return;\n\n  if (anchorClient) {\n    const rect = elements.routeMap.getBoundingClientRect();\n    const screen = {\n      x: anchorClient.x - rect.left,\n      y: anchorClient.y - rect.top,\n    };\n    const anchorLatLng = screenToLatLng(screen.x, screen.y);\n    mapState.zoom = zoom;\n    const anchorWorld = latLngToWorld(anchorLatLng, mapState.zoom);\n    mapState.center = worldToLatLng(\n      anchorWorld.x - (screen.x - rect.width / 2),\n      anchorWorld.y - (screen.y - rect.height / 2),\n      mapState.zoom\n    );\n  } else {\n    mapState.zoom = zoom;\n  }\n\n  renderMap();\n}\n\nfunction scheduleRenderMap() {\n  if (mapState.renderFrame) return;\n  mapState.renderFrame = requestAnimationFrame(() => {\n    mapState.renderFrame = null;\n    renderMap();\n  });\n}\n\nfunction panMap(direction) {\n  const amount = 150;\n  const offsets = {\n    north: [0, -amount],\n    east: [amount, 0],\n    south: [0, amount],\n    west: [-amount, 0],\n  };\n  const offset = offsets[direction];\n  if (!offset) return;\n  panByPixels(offset[0], offset[1]);\n}\n\nfunction panByPixels(dx, dy) {\n  const centerWorld = latLngToWorld(mapState.center, mapState.zoom);\n  mapState.center = worldToLatLng(centerWorld.x + dx, centerWorld.y + dy, mapState.zoom);\n  renderMap();\n}\n\nasync function addRoutePoint(latlng) {\n  const point = {\n    lat: roundCoord(latlng.lat),\n    lng: roundCoord(latlng.lng),\n    roadName: \"Finder vejnavn...\",\n  };\n  getActiveRoute().points.push(point);\n  state.lastMatches = [];\n  renderAll();\n  saveState();\n\n  point.roadName = await lookupRoadName(point.lat, point.lng);\n  renderAll();\n  saveState();\n  showToast(`Rutepunkt tilføjet: ${point.roadName}`);\n}\n\nfunction removeNearestRoutePoint(screenX, screenY) {\n  const points = getValidRoutePoints();\n  if (!points.length) return false;\n\n  const nearest = points.reduce(\n    (best, point, index) => {\n      const screenPoint = latLngToScreen(point);\n      const distance = Math.hypot(screenPoint.x - screenX, screenPoint.y - screenY);\n      return distance < best.distance ? { index, distance } : best;\n    },\n    { index: -1, distance: Number.POSITIVE_INFINITY }\n  );\n\n  if (nearest.index < 0 || nearest.distance > 28) return false;\n\n  getActiveRoute().points.splice(nearest.index, 1);\n  state.lastMatches = [];\n  renderAll();\n  saveState();\n  return true;\n}\n\nfunction runTrafficCheck() {\n  const route = getValidRoutePoints();\n  if (route.length < 2) {\n    showToast(\"Tilføj mindst to rutepunkter før tjek.\");\n    return;\n  }\n\n  const activeWindow = state.routeMode === \"work\"\n    ? [state.schedule.departFrom, state.schedule.departTo]\n    : [state.schedule.returnFrom, state.schedule.returnTo];\n  const routeRoads = new Set(getRouteSegments().map((segment) => normalizeName(segment.name)));\n\n  const matches = simulatedEvents\n    .map((event) => ({\n      ...event,\n      distanceMeters: Math.round(distanceToRouteMeters(event, route)),\n    }))\n    .filter((event) => {\n      const roadMatch = routeRoads.has(normalizeName(event.roadName));\n      const geometryMatch = event.distanceMeters <= event.radiusMeters;\n      const severityOverride = event.severity === \"high\";\n      return (\n        (roadMatch || geometryMatch) &&\n        windowsOverlap(event.window, activeWindow[0], activeWindow[1]) &&\n        (event.delay >= state.schedule.minDelay || severityOverride)\n      );\n    });\n\n  state.lastMatches = matches;\n  state.lastCheck = new Date().toISOString();\n  elements.systemStatus.textContent = matches.length ? `${matches.length} relevant alarm` : \"Ingen relevante alarmer\";\n  renderMatches(matches);\n  sendMessages(matches);\n  saveState();\n  showToast(matches.length ? \"Tjekket fandt relevante trafikale problemer.\" : \"Ruten ser fri ud i det valgte tidsrum.\");\n}\n\nfunction sendMessages(matches) {\n  if (!matches.length) return;\n\n  const strongest = [...matches].sort((a, b) => b.delay - a.delay)[0];\n  const title = `Trafikalarm: ${strongest.roadName}`;\n  const body = `${strongest.type}: ${strongest.title}. Forvent cirka ${strongest.delay} min ekstra på ruten ${routeLabel().toLowerCase()}.`;\n  const time = new Intl.DateTimeFormat(\"da-DK\", {\n    hour: \"2-digit\",\n    minute: \"2-digit\",\n  }).format(new Date());\n\n  if (state.schedule.channels.push) {\n    state.inbox.unshift({ title, body, time, channel: \"push\" });\n    if (\"Notification\" in window && Notification.permission === \"granted\") {\n      new Notification(title, {\n        body,\n        tag: strongest.id,\n      });\n    }\n  }\n\n  if (state.schedule.channels.email) {\n    state.inbox.unshift({\n      title: `Mail: ${strongest.roadName}`,\n      body: `${body} Modtager: ${state.user.email || \"ikke angivet\"}.`,\n      time,\n      channel: \"mail\",\n    });\n  }\n\n  state.inbox = state.inbox.slice(0, 12);\n  renderInbox();\n}\n\nasync function requestNotifications() {\n  if (!(\"Notification\" in window)) {\n    showToast(\"Browseren understøtter ikke push-notifikationer.\");\n    return;\n  }\n\n  if (Notification.permission === \"granted\") {\n    showToast(\"Push er allerede aktiveret.\");\n    return;\n  }\n\n  const permission = await Notification.requestPermission();\n  showToast(permission === \"granted\" ? \"Push er aktiveret.\" : \"Push blev ikke aktiveret.\");\n}\n\nfunction setSampleRoute(mode) {\n  const endpoints = getAddressEndpoints(mode);\n  if (endpoints) {\n    state.routes[mode].points = endpoints;\n    return;\n  }\n\n  state.routes[mode].points = sampleRoutes[mode].map((point) => ({ ...point }));\n}\n\nfunction getAddressEndpoints(mode) {\n  const start = mode === \"work\" ? state.user.homeLocation : state.user.workLocation;\n  const end = mode === \"work\" ? state.user.workLocation : state.user.homeLocation;\n  if (!start || !end) return null;\n\n  return [\n    {\n      lat: start.lat,\n      lng: start.lng,\n      roadName: start.roadName || start.label || \"Start\",\n    },\n    {\n      lat: end.lat,\n      lng: end.lng,\n      roadName: end.roadName || end.label || \"Slut\",\n    },\n  ];\n}\n\nfunction getActiveRoute() {\n  return state.routes[state.routeMode];\n}\n\nfunction getValidRoutePoints() {\n  return getActiveRoute().points.filter((point) => Number.isFinite(point.lat) && Number.isFinite(point.lng));\n}\n\nfunction getRouteSegments() {\n  const byName = new Map();\n  getValidRoutePoints().forEach((point) => {\n    const name = point.roadName || \"Ukendt vej\";\n    const normalized = normalizeName(name);\n    if (!normalized || normalized === normalizeName(\"Finder vejnavn...\")) return;\n    if (!byName.has(normalized)) {\n      byName.set(normalized, {\n        id: normalized,\n        name,\n      });\n    }\n  });\n  return Array.from(byName.values());\n}\n\nfunction routeLabel() {\n  return state.routeMode === \"work\" ? \"Til arbejde\" : \"Hjem\";\n}\n\nfunction fitActiveRoute() {\n  if (!mapState) return;\n  const points = getValidRoutePoints();\n  if (!points.length) {\n    mapState.center = { ...COPENHAGEN_CENTER };\n    mapState.zoom = 12;\n    renderMap();\n    return;\n  }\n\n  const bounds = points.reduce(\n    (acc, point) => ({\n      north: Math.max(acc.north, point.lat),\n      south: Math.min(acc.south, point.lat),\n      east: Math.max(acc.east, point.lng),\n      west: Math.min(acc.west, point.lng),\n    }),\n    { north: -90, south: 90, east: -180, west: 180 }\n  );\n  mapState.center = {\n    lat: (bounds.north + bounds.south) / 2,\n    lng: (bounds.east + bounds.west) / 2,\n  };\n\n  const rect = elements.routeMap.getBoundingClientRect();\n  for (let zoom = MAX_ZOOM; zoom >= MIN_ZOOM; zoom -= 1) {\n    const projected = points.map((point) => latLngToWorld(point, zoom));\n    const xs = projected.map((point) => point.x);\n    const ys = projected.map((point) => point.y);\n    const width = Math.max(...xs) - Math.min(...xs);\n    const height = Math.max(...ys) - Math.min(...ys);\n    if (width <= rect.width - 84 && height <= rect.height - 84) {\n      mapState.zoom = Math.min(zoom, 15);\n      break;\n    }\n  }\n\n  renderMap();\n}\n\nasync function lookupRoadName(lat, lng) {\n  const cacheKey = `${lat.toFixed(5)},${lng.toFixed(5)}`;\n  if (roadNameCache.has(cacheKey)) return roadNameCache.get(cacheKey);\n\n  try {\n    const url = new URL(NOMINATIM_URL);\n    url.searchParams.set(\"format\", \"jsonv2\");\n    url.searchParams.set(\"lat\", String(lat));\n    url.searchParams.set(\"lon\", String(lng));\n    url.searchParams.set(\"zoom\", \"18\");\n    url.searchParams.set(\"addressdetails\", \"1\");\n\n    const response = await fetch(url.toString(), {\n      headers: { Accept: \"application/json\" },\n    });\n    if (!response.ok) throw new Error(\"Reverse geocoding failed\");\n\n    const data = await response.json();\n    const address = data.address || {};\n    const roadName =\n      address.road ||\n      address.pedestrian ||\n      address.cycleway ||\n      address.footway ||\n      address.path ||\n      address.neighbourhood ||\n      address.suburb ||\n      (data.display_name || \"\").split(\",\")[0] ||\n      \"Ukendt vej\";\n\n    roadNameCache.set(cacheKey, roadName);\n    return roadName;\n  } catch {\n    roadNameCache.set(cacheKey, \"Ukendt vej\");\n    return \"Ukendt vej\";\n  }\n}\n\nfunction latLngToWorld(point, zoom) {\n  const scale = TILE_SIZE * 2 ** zoom;\n  const lat = Math.max(-85.05112878, Math.min(85.05112878, point.lat));\n  const sinLat = Math.sin((lat * Math.PI) / 180);\n  return {\n    x: ((point.lng + 180) / 360) * scale,\n    y: (0.5 - Math.log((1 + sinLat) / (1 - sinLat)) / (4 * Math.PI)) * scale,\n  };\n}\n\nfunction worldToLatLng(x, y, zoom) {\n  const scale = TILE_SIZE * 2 ** zoom;\n  const lng = (x / scale) * 360 - 180;\n  const n = Math.PI - (2 * Math.PI * y) / scale;\n  const lat = (180 / Math.PI) * Math.atan(0.5 * (Math.exp(n) - Math.exp(-n)));\n  return {\n    lat: Math.max(-85.05112878, Math.min(85.05112878, lat)),\n    lng: ((lng + 540) % 360) - 180,\n  };\n}\n\nfunction screenToLatLng(x, y) {\n  const rect = elements.routeMap.getBoundingClientRect();\n  const centerWorld = latLngToWorld(mapState.center, mapState.zoom);\n  const topLeft = {\n    x: centerWorld.x - rect.width / 2,\n    y: centerWorld.y - rect.height / 2,\n  };\n  return worldToLatLng(topLeft.x + x, topLeft.y + y, mapState.zoom);\n}\n\nfunction latLngToScreen(point) {\n  const rect = elements.routeMap.getBoundingClientRect();\n  const centerWorld = latLngToWorld(mapState.center, mapState.zoom);\n  const world = latLngToWorld(point, mapState.zoom);\n  return {\n    x: world.x - (centerWorld.x - rect.width / 2),\n    y: world.y - (centerWorld.y - rect.height / 2),\n  };\n}\n\nfunction distanceToRouteMeters(point, route) {\n  if (route.length === 1) return haversineMeters(point, route[0]);\n\n  let best = Number.POSITIVE_INFINITY;\n  for (let index = 0; index < route.length - 1; index += 1) {\n    const distance = pointToSegmentDistanceMeters(point, route[index], route[index + 1]);\n    best = Math.min(best, distance);\n  }\n  return best;\n}\n\nfunction pointToSegmentDistanceMeters(point, start, end) {\n  const latOrigin = (point.lat * Math.PI) / 180;\n  const project = (candidate) => ({\n    x: candidate.lng * 111320 * Math.cos(latOrigin),\n    y: candidate.lat * 110540,\n  });\n  const p = project(point);\n  const a = project(start);\n  const b = project(end);\n  const dx = b.x - a.x;\n  const dy = b.y - a.y;\n  const lengthSquared = dx * dx + dy * dy;\n  if (!lengthSquared) return Math.hypot(p.x - a.x, p.y - a.y);\n  const t = Math.max(0, Math.min(1, ((p.x - a.x) * dx + (p.y - a.y) * dy) / lengthSquared));\n  const closest = {\n    x: a.x + t * dx,\n    y: a.y + t * dy,\n  };\n  return Math.hypot(p.x - closest.x, p.y - closest.y);\n}\n\nfunction haversineMeters(a, b) {\n  const radius = 6371000;\n  const lat1 = (a.lat * Math.PI) / 180;\n  const lat2 = (b.lat * Math.PI) / 180;\n  const deltaLat = ((b.lat - a.lat) * Math.PI) / 180;\n  const deltaLng = ((b.lng - a.lng) * Math.PI) / 180;\n  const value =\n    Math.sin(deltaLat / 2) * Math.sin(deltaLat / 2) +\n    Math.cos(lat1) * Math.cos(lat2) * Math.sin(deltaLng / 2) * Math.sin(deltaLng / 2);\n  return radius * 2 * Math.atan2(Math.sqrt(value), Math.sqrt(1 - value));\n}\n\nfunction windowsOverlap(eventWindow, start, end) {\n  const [eventStart, eventEnd] = eventWindow.split(\"-\").map(toMinutes);\n  const startMinutes = toMinutes(start);\n  const endMinutes = toMinutes(end);\n  return eventStart <= endMinutes && eventEnd >= startMinutes;\n}\n\nfunction toMinutes(value) {\n  const [hours, minutes] = value.split(\":\").map(Number);\n  return hours * 60 + minutes;\n}\n\nfunction normalizeName(value) {\n  return (value || \"\")\n    .toLocaleLowerCase(\"da-DK\")\n    .normalize(\"NFD\")\n    .replace(/[\\u0300-\\u036f]/g, \"\")\n    .replace(/\\s+/g, \" \")\n    .trim();\n}\n\nfunction createSvg(tag, attributes = {}) {\n  const node = document.createElementNS(SVG_NS, tag);\n  Object.entries(attributes).forEach(([key, value]) => node.setAttribute(key, value));\n  return node;\n}\n\nfunction roundCoord(value) {\n  return Math.round(Number(value) * 1000000) / 1000000;\n}\n\nfunction showToast(message) {\n  elements.toast.textContent = message;\n  elements.toast.classList.add(\"show\");\n  clearTimeout(showToast.timer);\n  showToast.timer = setTimeout(() => elements.toast.classList.remove(\"show\"), 2600);\n}\n\nfunction registerServiceWorker() {\n  if (location.protocol.startsWith(\"http\") && \"serviceWorker\" in navigator) {\n    navigator.serviceWorker.register(\"service-worker.js\").catch(() => {\n      // The app still works without offline caching.\n    });\n  }\n}\n","type":"text/javascript; charset=utf-8"},"/manifest.json":{"body":"{\n  \"name\": \"Trafikalarm\",\n  \"short_name\": \"Trafikalarm\",\n  \"description\": \"Pendlerovervågning med ruter, tidsvinduer og trafikvarsler.\",\n  \"start_url\": \"./index.html\",\n  \"display\": \"standalone\",\n  \"background_color\": \"#f4f1e9\",\n  \"theme_color\": \"#0f766e\",\n  \"icons\": [\n    {\n      \"src\": \"icon.svg\",\n      \"sizes\": \"any\",\n      \"type\": \"image/svg+xml\",\n      \"purpose\": \"any\"\n    }\n  ]\n}\n","type":"application/json; charset=utf-8"},"/service-worker.js":{"body":"const CACHE_NAME = \"trafikalarm-prototype-v3\";\nconst ASSETS = [\n  \"./\",\n  \"./index.html\",\n  \"./styles.css\",\n  \"./app.js\",\n  \"./manifest.json\",\n  \"./icon.svg\",\n];\n\nself.addEventListener(\"install\", (event) => {\n  event.waitUntil(caches.open(CACHE_NAME).then((cache) => cache.addAll(ASSETS)));\n});\n\nself.addEventListener(\"activate\", (event) => {\n  event.waitUntil(\n    caches\n      .keys()\n      .then((keys) => Promise.all(keys.filter((key) => key !== CACHE_NAME).map((key) => caches.delete(key))))\n  );\n});\n\nself.addEventListener(\"fetch\", (event) => {\n  if (event.request.method !== \"GET\") return;\n  event.respondWith(caches.match(event.request).then((cached) => cached || fetch(event.request)));\n});\n","type":"text/javascript; charset=utf-8"},"/icon.svg":{"body":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 512 512\">\n  <rect width=\"512\" height=\"512\" rx=\"72\" fill=\"#17201f\"/>\n  <path d=\"M122 348c54-100 111-159 171-178 24-8 52-11 84-10\" fill=\"none\" stroke=\"#fffdf8\" stroke-width=\"40\" stroke-linecap=\"round\"/>\n  <path d=\"M130 354c37 9 80 12 128 8 60-6 103-25 129-58\" fill=\"none\" stroke=\"#0f766e\" stroke-width=\"34\" stroke-linecap=\"round\"/>\n  <circle cx=\"350\" cy=\"154\" r=\"52\" fill=\"#cc5538\"/>\n  <path d=\"M350 122v44\" stroke=\"#fffdf8\" stroke-width=\"26\" stroke-linecap=\"round\"/>\n  <circle cx=\"350\" cy=\"193\" r=\"13\" fill=\"#fffdf8\"/>\n</svg>\n","type":"image/svg+xml; charset=utf-8"},"/":{"body":"<!doctype html>\n<html lang=\"da\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <meta name=\"theme-color\" content=\"#0f766e\" />\n    <title>Trafikalarm</title>\n    <link rel=\"manifest\" href=\"manifest.json\" />\n    <link rel=\"stylesheet\" href=\"styles.css\" />\n  </head>\n  <body>\n    <svg class=\"icon-sprite\" aria-hidden=\"true\">\n      <symbol id=\"icon-bell\" viewBox=\"0 0 24 24\">\n        <path d=\"M6 9a6 6 0 1 1 12 0c0 7 3 6 3 8H3c0-2 3-1 3-8Z\"></path>\n        <path d=\"M10 21h4\"></path>\n      </symbol>\n      <symbol id=\"icon-route\" viewBox=\"0 0 24 24\">\n        <circle cx=\"6\" cy=\"19\" r=\"3\"></circle>\n        <circle cx=\"18\" cy=\"5\" r=\"3\"></circle>\n        <path d=\"M9 19h2a5 5 0 0 0 0-10H9a3 3 0 0 1 0-6h6\"></path>\n      </symbol>\n      <symbol id=\"icon-play\" viewBox=\"0 0 24 24\">\n        <path d=\"m8 5 11 7-11 7Z\"></path>\n      </symbol>\n      <symbol id=\"icon-pen\" viewBox=\"0 0 24 24\">\n        <path d=\"M12 20h9\"></path>\n        <path d=\"M16.5 3.5a2.1 2.1 0 0 1 3 3L7 19l-4 1 1-4Z\"></path>\n      </symbol>\n      <symbol id=\"icon-trash\" viewBox=\"0 0 24 24\">\n        <path d=\"M3 6h18\"></path>\n        <path d=\"M8 6V4h8v2\"></path>\n        <path d=\"M6 6l1 15h10l1-15\"></path>\n      </symbol>\n      <symbol id=\"icon-mail\" viewBox=\"0 0 24 24\">\n        <path d=\"M4 5h16v14H4Z\"></path>\n        <path d=\"m4 7 8 6 8-6\"></path>\n      </symbol>\n      <symbol id=\"icon-user\" viewBox=\"0 0 24 24\">\n        <circle cx=\"12\" cy=\"8\" r=\"4\"></circle>\n        <path d=\"M4 21a8 8 0 0 1 16 0\"></path>\n      </symbol>\n    </svg>\n\n    <div class=\"app-shell\">\n      <header class=\"topbar\">\n        <div class=\"brand\">\n          <div class=\"brand-mark\">TA</div>\n          <div>\n            <h1>Trafikalarm</h1>\n            <p>Rutevarsling til pendleren</p>\n          </div>\n        </div>\n        <div class=\"topbar-actions\">\n          <div class=\"system-status\" id=\"systemStatus\">Klar til tjek</div>\n          <button class=\"button secondary\" id=\"requestNotifications\" type=\"button\">\n            <svg><use href=\"#icon-bell\"></use></svg>\n            Aktiver push\n          </button>\n        </div>\n      </header>\n\n      <main class=\"workspace\">\n        <section class=\"auth-banner\" id=\"authBanner\">\n          <div>\n            <strong>Opret din pendlerprofil</strong>\n            <span>Prototypen gemmer dine valg lokalt i browseren.</span>\n          </div>\n          <form id=\"quickProfileForm\" class=\"quick-profile\">\n            <label>\n              Navn\n              <input id=\"quickName\" name=\"quickName\" autocomplete=\"name\" placeholder=\"Dit navn\" />\n            </label>\n            <label>\n              Mail\n              <input id=\"quickEmail\" name=\"quickEmail\" type=\"email\" autocomplete=\"email\" placeholder=\"navn@example.dk\" />\n            </label>\n            <button class=\"button primary\" type=\"submit\">Gem profil</button>\n          </form>\n        </section>\n\n        <section class=\"panel profile-panel\" aria-labelledby=\"profileTitle\">\n          <div class=\"panel-heading\">\n            <div>\n              <p class=\"eyebrow\">Profil</p>\n              <h2 id=\"profileTitle\">Pendler og tider</h2>\n            </div>\n            <svg class=\"panel-icon\"><use href=\"#icon-user\"></use></svg>\n          </div>\n\n          <form id=\"profileForm\" class=\"form-stack\">\n            <div class=\"field-grid\">\n              <label>\n                Navn\n                <input id=\"nameInput\" name=\"name\" autocomplete=\"name\" placeholder=\"Dit navn\" />\n              </label>\n              <label>\n                Mail til varsler\n                <input id=\"emailInput\" name=\"email\" type=\"email\" autocomplete=\"email\" placeholder=\"navn@example.dk\" />\n              </label>\n            </div>\n\n            <div class=\"field-grid\">\n              <label>\n                Hjem\n                <input id=\"homeInput\" name=\"home\" list=\"homeSuggestions\" autocomplete=\"street-address\" placeholder=\"fx Frederiksberg\" />\n                <datalist id=\"homeSuggestions\"></datalist>\n              </label>\n              <label>\n                Arbejde\n                <input id=\"workInput\" name=\"work\" list=\"workSuggestions\" autocomplete=\"street-address\" placeholder=\"fx Nordhavn\" />\n                <datalist id=\"workSuggestions\"></datalist>\n              </label>\n            </div>\n\n            <div class=\"section-label\">Rute</div>\n            <div class=\"segmented\" role=\"tablist\" aria-label=\"Vælg rute\">\n              <button class=\"segment active\" id=\"modeWork\" type=\"button\" data-mode=\"work\">Til arbejde</button>\n              <button class=\"segment\" id=\"modeHome\" type=\"button\" data-mode=\"home\">Hjem</button>\n            </div>\n\n            <div class=\"section-label\">Ugedage</div>\n            <div class=\"days\" id=\"daysGroup\" aria-label=\"Vælg dage\">\n              <label><input type=\"checkbox\" value=\"mon\" /> Man</label>\n              <label><input type=\"checkbox\" value=\"tue\" /> Tir</label>\n              <label><input type=\"checkbox\" value=\"wed\" /> Ons</label>\n              <label><input type=\"checkbox\" value=\"thu\" /> Tor</label>\n              <label><input type=\"checkbox\" value=\"fri\" /> Fre</label>\n              <label><input type=\"checkbox\" value=\"sat\" /> Lør</label>\n              <label><input type=\"checkbox\" value=\"sun\" /> Søn</label>\n            </div>\n\n            <div class=\"time-grid\">\n              <label>\n                Morgen fra\n                <input id=\"departFrom\" type=\"time\" />\n              </label>\n              <label>\n                Morgen til\n                <input id=\"departTo\" type=\"time\" />\n              </label>\n              <label>\n                Hjem fra\n                <input id=\"returnFrom\" type=\"time\" />\n              </label>\n              <label>\n                Hjem til\n                <input id=\"returnTo\" type=\"time\" />\n              </label>\n            </div>\n\n            <div class=\"range-row\">\n              <label for=\"leadInput\">Varsl før afgang</label>\n              <input id=\"leadInput\" type=\"range\" min=\"5\" max=\"60\" step=\"5\" />\n              <output id=\"leadOutput\"></output>\n            </div>\n            <div class=\"range-row\">\n              <label for=\"delayInput\">Minimum forsinkelse</label>\n              <input id=\"delayInput\" type=\"range\" min=\"0\" max=\"30\" step=\"1\" />\n              <output id=\"delayOutput\"></output>\n            </div>\n\n            <div class=\"channel-row\">\n              <label class=\"switch\">\n                <input id=\"pushChannel\" type=\"checkbox\" />\n                <span></span>\n                Push\n              </label>\n              <label class=\"switch\">\n                <input id=\"emailChannel\" type=\"checkbox\" />\n                <span></span>\n                Mail\n              </label>\n            </div>\n\n            <button class=\"button primary full\" type=\"submit\">Gem ændringer</button>\n          </form>\n        </section>\n\n        <section class=\"panel map-panel\" aria-labelledby=\"mapTitle\">\n          <div class=\"panel-heading map-heading\">\n            <div>\n              <p class=\"eyebrow\">Kort</p>\n              <h2 id=\"mapTitle\">Tegn eller foreslå ruten</h2>\n            </div>\n            <div class=\"map-actions\">\n              <button class=\"button secondary\" id=\"sampleRoute\" type=\"button\">\n                <svg><use href=\"#icon-route\"></use></svg>\n                Foreslå rute\n              </button>\n              <button class=\"button secondary\" id=\"drawToggle\" type=\"button\" aria-pressed=\"true\">\n                <svg><use href=\"#icon-pen\"></use></svg>\n                Tegn\n              </button>\n              <button class=\"icon-button\" id=\"clearRoute\" type=\"button\" aria-label=\"Ryd rute\" title=\"Ryd rute\">\n                <svg><use href=\"#icon-trash\"></use></svg>\n              </button>\n            </div>\n          </div>\n\n          <div class=\"map-frame\">\n            <div id=\"routeMap\" role=\"application\" aria-label=\"OpenStreetMap-kort til at plotte pendlerute\"></div>\n            <div class=\"map-help\" id=\"mapHelp\">Klik på kortet for at sætte rutepunkter. Appen forsøger at finde vejnavnet for hvert punkt.</div>\n          </div>\n        </section>\n\n        <section class=\"panel monitor-panel\" aria-labelledby=\"monitorTitle\">\n          <div class=\"panel-heading\">\n            <div>\n              <p class=\"eyebrow\">Overvågning</p>\n              <h2 id=\"monitorTitle\">Alarmstatus</h2>\n            </div>\n            <button class=\"button primary\" id=\"runCheck\" type=\"button\">\n              <svg><use href=\"#icon-play\"></use></svg>\n              Kør tjek\n            </button>\n          </div>\n\n          <div class=\"status-tile\" id=\"nextTripTile\">\n            <span>Næste tjek</span>\n            <strong>Ikke beregnet endnu</strong>\n          </div>\n\n          <div class=\"info-block\">\n            <div class=\"info-heading\">\n              <h3>Genkendte veje</h3>\n              <span id=\"segmentCount\">0</span>\n            </div>\n            <div class=\"chips\" id=\"roadChips\"></div>\n          </div>\n\n          <div class=\"info-block\">\n            <div class=\"info-heading\">\n              <h3>Aktuelle hændelser</h3>\n              <span id=\"matchCount\">0</span>\n            </div>\n            <div class=\"event-list\" id=\"eventList\"></div>\n          </div>\n\n          <div class=\"info-block\">\n            <div class=\"info-heading\">\n              <h3>Beskeder</h3>\n              <button class=\"text-button\" id=\"clearInbox\" type=\"button\">Ryd</button>\n            </div>\n            <div class=\"inbox\" id=\"inbox\"></div>\n          </div>\n        </section>\n      </main>\n    </div>\n\n    <div class=\"toast\" id=\"toast\" role=\"status\" aria-live=\"polite\"></div>\n\n    <script src=\"app.js\" defer></script>\n  </body>\n</html>\n","type":"text/html; charset=utf-8"}};

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname.endsWith("/") && url.pathname !== "/" ? url.pathname.slice(0, -1) : url.pathname;
    const asset = ASSETS[path] || ASSETS[path + ".html"] || ASSETS["/index.html"];
    const headers = new Headers({
      "content-type": asset.type,
      "cache-control": path === "/index.html" || path === "/" ? "no-store" : "public, max-age=3600",
    });
    return new Response(asset.body, { headers });
  },
};
